import { Component, Element, Event, EventEmitter, h, Host, Method, Prop, State } from '@stencil/core';
import { customTwMerge, generateRandId } from '../../../utils/utils';

@Component({
  tag: 'wdpr-dual-combobox-item',
  styleUrl: 'wdpr-dual-combobox-item.css',
  shadow: true,
})
export class WdprDualComboboxItem {
  private _internalId: string;

  @Element() el: HTMLWdprDualComboboxItemElement;

  @State() _hideDivider: boolean = false;

  @Prop() itemId: string;
  @Prop() value: string;
  @Prop() label: string;
  @Prop() description: string;
  @Prop({ reflect: true }) disabled: boolean = false;
  @Prop({ reflect: true }) selected: boolean = false;
  @Prop() isFocused: boolean = false;
  @Prop() isHidden: boolean = false;

  @Event() wdprSelect: EventEmitter<{ value: string; label: string; selected: boolean; id: string }>;

  @Method()
  async hideDivider() {
    this._hideDivider = true;
  }

  @Method()
  async showDivider() {
    this._hideDivider = false;
  }

  componentWillLoad() {
    this._internalId = this.itemId || `wdpr-combobox-item-${generateRandId()}`;
  }

  private _handleSelection() {
    if (this.disabled) return;

    this.wdprSelect.emit({ value: this.value, label: this.label, selected: !this.selected, id: this._internalId });
  }

  private get _singleSelectionClasses() {
    return customTwMerge(
      itemClasses,
      this.selected ? itemSelectedClasses : itemUnselectedBaseClasses,
      this.isFocused && itemFocusedClasses,
      this.disabled && itemDisabledClasses,
      !this.disabled && itemEnabledClasses,
    );
  }

  render() {
    return (
      <Host
        id={this._internalId}
        role="option"
        data-dual-combobox-item
        aria-selected={this.selected.toString()}
        aria-disabled={this.disabled.toString()}
        onClick={() => this._handleSelection()}
        class={`${this.isHidden ? 'hidden' : ''}`}
      >
        <div class={this._singleSelectionClasses}>
          <slot name="icon" />
          <div class="flex flex-col gap-050 items-start">
            {this.label && <span class="body-large text-start line-clamp-2">{this.label}</span>}
            {this.description && <span class="body-small text-start line-clamp-2">{this.description}</span>}
          </div>
        </div>
        {!this._hideDivider && (
          <div class="mx-100" aria-hidden="true">
            <wdpr-divider />
          </div>
        )}
      </Host>
    );
  }
}

const itemClasses = `item flex items-start gap-100 p-100 w-full rounded-100 cursor-pointer transition-colors bg-surface-transparent text-text-actionable-alt-default`;
const itemFocusedClasses = `outline-037 outline-solid outline-offset-1 outline-stroke-actionable-alt-focused`;
const itemDisabledClasses = 'bg-color-surface-transparent text-text-actionable-alt-disabled cursor-not-allowed';

const itemUnselectedBaseClasses = `bg-surface-transparent text-text-actionable-alt-default`;
const itemSelectedClasses = `bg-surface-actionable-alt-pressed text-text-actionable-inverse-default`;
const itemEnabledClasses = `hover:bg-surface-actionable-alt-hover hover:text-text-actionable-inverse-default
active:bg-surface-actionable-alt-pressed active:text-text-actionable-inverse-default`;
